const functions = require('@google-cloud/functions-framework');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

function getEnv(name, required = true) {
  const value = process.env[name];
  if (required && (!value || !String(value).trim())) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function initializeClients() {
  const sendGridApiKey = getEnv('SENDGRID_API_KEY');
  const twilioAccountSid = getEnv('TWILIO_ACCOUNT_SID');
  const twilioAuthToken = getEnv('TWILIO_AUTH_TOKEN');

  sgMail.setApiKey(sendGridApiKey);
  const twilioClient = twilio(twilioAccountSid, twilioAuthToken);

  return { twilioClient };
}

const { twilioClient } = initializeClients();

async function sendEmail({ to, from, subject, text, html, cc, bcc, replyTo }) {
  const msg = {
    to,
    from: from || getEnv('SENDGRID_FROM_EMAIL'),
    subject,
    text,
    html,
    cc,
    bcc,
    replyTo,
  };

  Object.keys(msg).forEach((key) => {
    if (msg[key] === undefined || msg[key] === null || msg[key] === '') {
      delete msg[key];
    }
  });

  const [response] = await sgMail.send(msg);
  return {
    service: 'sendgrid',
    statusCode: response.statusCode,
    headers: response.headers,
  };
}

async function sendSms({ to, body, from, messagingServiceSid }) {
  const payload = {
    to,
    body,
  };

  if (messagingServiceSid) {
    payload.messagingServiceSid = messagingServiceSid;
  } else {
    payload.from = from || getEnv('TWILIO_FROM_NUMBER');
  }

  const message = await twilioClient.messages.create(payload);
  return {
    service: 'twilio',
    sid: message.sid,
    status: message.status,
    to: message.to,
    from: message.from,
  };
}

function validateRequestBody(body) {
  if (!body || typeof body !== 'object') {
    throw new Error('Request body must be a JSON object');
  }

  const hasEmail = !!body.email;
  const hasSms = !!body.sms;

  if (!hasEmail && !hasSms) {
    throw new Error('Request must include at least one of: email, sms');
  }

  if (hasEmail) {
    const email = body.email;
    if (!email.to) throw new Error('email.to is required');
    if (!email.subject) throw new Error('email.subject is required');
    if (!email.text && !email.html) throw new Error('email.text or email.html is required');
  }

  if (hasSms) {
    const sms = body.sms;
    if (!sms.to) throw new Error('sms.to is required');
    if (!sms.body) throw new Error('sms.body is required');
  }
}

functions.http('notify', async (req, res) => {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed. Use POST.' });
  }

  try {
    validateRequestBody(req.body);

    const tasks = [];

    if (req.body.email) {
      tasks.push(
        sendEmail(req.body.email).then((result) => ({
          channel: 'email',
          success: true,
          result,
        }))
      );
    }

    if (req.body.sms) {
      tasks.push(
        sendSms(req.body.sms).then((result) => ({
          channel: 'sms',
          success: true,
          result,
        }))
      );
    }

    const settled = await Promise.allSettled(tasks);

    const results = settled.map((item) => {
      if (item.status === 'fulfilled') return item.value;
      return {
        success: false,
        error: item.reason && item.reason.message ? item.reason.message : 'Unknown error',
      };
    });

    const allSucceeded = results.every((r) => r.success);

    return res.status(allSucceeded ? 200 : 207).json({
      success: allSucceeded,
      results,
    });
  } catch (error) {
    return res.status(400).json({
      success: false,
      error: error.message || 'Bad request',
    });
  }
});